BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?viewName ?inFlowDown ?inIndividual WHERE {
  {
    SELECT DISTINCT ?supplier ?supplierName WHERE {
      ?zznext rdf:type vocab:zznext .
      ?zznext vocab:Dependency_supplier ?supplier .
      OPTIONAL { ?supplier vocab:NamedElement_name ?supplierName }
      ?zznext vocab:Element_owner ?owner .
      FILTER(CONTAINS(STR(?owner), "Flow-down"))
    }
  }
  BIND(true AS ?inFlowDown)
  OPTIONAL {
    ?zznext2 rdf:type vocab:zznext .
    ?zznext2 vocab:Dependency_supplier ?supplier .
    ?zznext2 vocab:Element_owner ?owner2 .
    FILTER(CONTAINS(STR(?owner2), "individual views"))
    BIND(true AS ?inIndividual)
  }
  ?supplier vocab:NamedElement_name ?viewName .
  FILTER(?inFlowDown && ?inIndividual)
}
ORDER BY ?viewName
LIMIT 50

